use ffec::{
    field_utils::{
        bigint::{GMP_NUMB_BITS, bigint},
        field_utils::batch_invert,
    },
    {
        BigInt, Fp_model, Fp_modelConfig, Fp2_model, Fp2_modelConfig, Fp3_modelConfig,
        Fp6_3over2_model, Fp6_modelConfig, Fp12_2over3over2_model, Fp12_modelConfig, One, PpConfig,
        Zero,
    },
};

use std::{
    borrow::Borrow,
    ops::{Add, Mul, Neg, Sub},
};

use super::fields::{fq::Fq, fq2::Fq2, fq6::Fq6, fq12::Fq12, fr::Fr};
use crate::algebra::curves::alt_bn128::{alt_bn128_g1::alt_bn128_G1, alt_bn128_g2::alt_bn128_G2};

pub const alt_bn128_r_bitcount: usize = 254;
pub const alt_bn128_q_bitcount: usize = 254;

pub const alt_bn128_r_limbs: usize = (alt_bn128_r_bitcount + GMP_NUMB_BITS - 1) / GMP_NUMB_BITS;
pub const alt_bn128_q_limbs: usize = (alt_bn128_q_bitcount + GMP_NUMB_BITS - 1) / GMP_NUMB_BITS;

pub const alt_bn128_q_limbs2: usize = alt_bn128_q_limbs * 2;
pub const alt_bn128_q_limbs3: usize = alt_bn128_q_limbs * 3;
pub const alt_bn128_q_limbs6: usize = alt_bn128_q_limbs * 6;
pub const alt_bn128_q_limbs12: usize = alt_bn128_q_limbs * 12;

pub type alt_bn128_Fr = Fp_model<alt_bn128_r_limbs, Backend>;
pub type alt_bn128_Fq = Fp_model<alt_bn128_q_limbs, Backend>;
pub type alt_bn128_Fq2 = Fp2_model<alt_bn128_q_limbs, alt_bn128_q_limbs2, Backend>;
pub type alt_bn128_Fq6 =
    Fp6_3over2_model<alt_bn128_q_limbs, alt_bn128_q_limbs2, alt_bn128_q_limbs6, Backend>;
pub type alt_bn128_Fq12 = Fp12_2over3over2_model<
    alt_bn128_q_limbs,
    alt_bn128_q_limbs2,
    alt_bn128_q_limbs6,
    alt_bn128_q_limbs12,
    Backend,
>;
pub type alt_bn128_GT = alt_bn128_Fq12;

#[macro_export]
macro_rules! new_fq2 {
    ($c0:expr ,$c1:expr  ) => {{
        alt_bn128_Fq2::const_new(
            alt_bn128_Fq::const_new(BigInt!($c0)),
            alt_bn128_Fq::const_new(BigInt!($c1)),
        )
    }};
}

#[macro_export]
macro_rules! new_fq6 {
    ($c0:expr ,$c1:expr ,$c2:expr  ) => {{ alt_bn128_Fq6::const_new(new_fq2!($c0), new_fq2!($c1), new_fq2!($c2)) }};
}

#[derive(Default, Clone, Debug, Copy, PartialEq, Eq)]
pub struct Backend;

